// Generated by generate.ts — hidden adversarial suite for state-machine.
// Run via `npx tsx __audit__/stateMachine.hidden.ts` inside the scratch project.
import { StateMachine } from '../src/stateMachine'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("initial state", new StateMachine("idle", []).getState(), "idle")
await check("transition", (() => { const m = new StateMachine("idle", [{from:"idle",event:"start",to:"running"}]); m.send("start"); return m.getState() })(), "running")
await check("send returns true on success", (() => { const m = new StateMachine("idle", [{from:"idle",event:"go",to:"on"}]); return m.send("go") })(), true)
await check("send returns false on miss", (() => { const m = new StateMachine("idle", []); return m.send("go" as any) })(), false)
await check("can check", (() => { const m = new StateMachine("idle", [{from:"idle",event:"go",to:"on"}]); return m.can("go") })(), true)
await check("guard blocks transition", (() => { const m = new StateMachine("idle", [{from:"idle",event:"go",to:"on",guard:()=>false}]); m.send("go"); return m.getState() })(), "idle")
await check("history tracking", (() => { const m = new StateMachine("a", [{from:"a",event:"go",to:"b"},{from:"b",event:"go",to:"c"}]); m.send("go"); m.send("go"); return m.getHistory() })(), ["a","b","c"])
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
